w:document.w:body:
{{/* ============================================================================
     HEADER
     ============================================================================ */}}

    {{/* Name - large, bold, centered */}}





        {{upper (escape .Contact.Name)}}



    {{/* Contact info line */}}
    {{- $contactParts := contactLine .Contact }}
    {{- if $contactParts }}





        {{escape $contactParts}}


    {{- end }}

    {{/* Spacing after header */}}



{{/* ============================================================================
     SECTION DEFINITIONS
     ============================================================================ */}}

{{- define "docx-section-summary" -}}
{{- if .Summary }}
    {{- template "docx-section-header" (dict "title" "Professional Summary") }}




        {{escape .Summary}}




{{- end }}
{{- end -}}

{{- define "docx-section-certifications" -}}
{{- if .Certifications }}
{{- if .Certifications.Items }}
    {{- template "docx-section-header" (dict "title" (default "Certifications" .Certifications.Title)) }}
    {{- range .Certifications.Items }}




        {{escape (certLine .)}}


    {{- end }}


{{- end }}
{{- end }}
{{- end -}}

{{- define "docx-section-education" -}}
{{- if .Education.Institutions }}
    {{- template "docx-section-header" (dict "title" (default "Education" .Education.Title)) }}
    {{- range sortEducationByOrder .Education.Institutions }}




        {{escape (eduHeader .)}}


    {{- if .GPA }}
    {{- $gpa := formatGPA .GPA }}
    {{- if $gpa }}




        GPA: {{escape $gpa}}


    {{- end }}
    {{- end }}
    {{- range filterEmpty .Degree.Descriptions }}




        • {{escape .}}


    {{- end }}
    {{- if .Thesis }}
    {{- $thesisLine := thesisLine .Thesis }}
    {{- if $thesisLine }}




        {{escape $thesisLine}}


    {{- end }}
    {{- end }}
    {{- end }}


{{- end }}
{{- end -}}

{{- define "docx-section-skills" -}}
{{- if .Skills.Categories }}
    {{- template "docx-section-header" (dict "title" (default "Skills" .Skills.Title)) }}
    {{- range .Skills.Categories }}




        • 



        {{escape .Category}}: 



        {{escape (join ", " (skillNames .Items))}}


    {{- end }}


{{- end }}
{{- end -}}

{{- define "docx-section-experience" -}}
{{- if .Experience.Positions }}
    {{- template "docx-section-header" (dict "title" (default "Experience" .Experience.Title)) }}
    {{- range sortExperienceByOrder .Experience.Positions }}




        {{escape (expTitleLine .)}}


    {{- $companyLine := expCompanyLine . }}
    {{- if $companyLine }}




        {{escape $companyLine}}


    {{- end }}
    {{- range .Highlights }}




        • {{escape .}}


    {{- end }}


    {{- end }}
{{- end }}
{{- end -}}

{{- define "docx-section-projects" -}}
{{- if .Projects }}
{{- if .Projects.Projects }}
    {{- template "docx-section-header" (dict "title" (default "Projects" .Projects.Title)) }}
    {{- range sortProjectsByOrder .Projects.Projects }}




        {{escape .Name}}


    {{- range .Highlights }}




        • {{escape .}}


    {{- end }}
    {{- if (trim .Link.URI) }}




          → {{escape .Link.URI}}


    {{- end }}
    {{- end }}


{{- end }}
{{- end }}
{{- end -}}

{{- define "docx-section-languages" -}}
{{- if .Languages }}
{{- if .Languages.Languages }}
    {{- template "docx-section-header" (dict "title" (default "Languages" .Languages.Title)) }}
    {{- range .Languages.Languages }}




        • {{escape (langLine .)}}


    {{- end }}


{{- end }}
{{- end }}
{{- end -}}

{{/* Section header sub-template */}}
{{- define "docx-section-header" -}}




        {{upper (escape .title)}}




{{- end -}}

{{/* ============================================================================
     SECTION DISPATCH
     ============================================================================ */}}

{{- $root := . -}}
{{- range .SectionOrder -}}
{{- if eq . "summary"}}{{template "docx-section-summary" $root}}
{{- else if eq . "certifications"}}{{template "docx-section-certifications" $root}}
{{- else if eq . "experience"}}{{template "docx-section-experience" $root}}
{{- else if eq . "education"}}{{template "docx-section-education" $root}}
{{- else if eq . "skills"}}{{template "docx-section-skills" $root}}
{{- else if eq . "projects"}}{{template "docx-section-projects" $root}}
{{- else if eq . "languages"}}{{template "docx-section-languages" $root}}
{{- end}}
{{- end}}

{{- if and .Layout .Layout.References }}







        References available upon request


{{- end }}
